import React, { useContext, useEffect, useState } from 'react';
import Button from '@mui/material/Button';
import { Grid } from '@mui/material';
// import UploadService from './services/upload-files.service';
import { ListingContext } from './contexts/ListingContext';
import { v4 as uuid } from 'uuid'
import { arrayMove } from 'react-sortable-hoc';
import ImageUploadGallery from './ImageUploadGallery';

export default function ImageUpload({ setImages }) {

  const { allImages, setAllImages, existingImages } = useContext(ListingContext)

  const [disabled, setDisabled] = useState(false)

  const maxImages = 14

  useEffect(() => {
    setImages([])
  }, [])

  useEffect(() => {
    setAllImages([...existingImages])
  }, [existingImages])

  const selectFiles = (event) => {
    let result = allImages
    for (let file of event.target.files) {
      if (allImages.length > maxImages) {
        setDisabled(true)
        break
      } else {
        result.push({ data: file, id: uuid(), tempURL: URL.createObjectURL(file) })
      }
    }
    setAllImages([...result])
    console.log(existingImages)
  }

  const onSortEnd = ({ oldIndex, newIndex }) => {
    setAllImages((allImages) => arrayMove(allImages, oldIndex, newIndex))
  };

  // const uploadImages = (e) => {
  //   e.preventDefault()
  //   UploadService.upload(allImages)
  // }

  const removeFile = (id) => {
    const result = allImages.filter(image => image.id !== id && image._id !== id)
    setDisabled(false)
    setAllImages([...result])
  }

  return (
    <Grid container gap={2}>
      <label htmlFor="images">
        <div className="form-group">
          <input
            id="images"
            name="images"
            style={{ display: 'none' }}
            type="file"
            accept="image/*"
            onChange={selectFiles}
            multiple
            disabled={disabled}
          />
        </div>
        <div className="form-group">
          <Button
            className="btn-choose"
            variant="outlined"
            component="span" >
            Choose Images
          </Button>
        </div>
        {/* <div className="form-group">
          <Button
            className="btn-choose"
            variant="outlined"
            component="span"
            onClick={uploadImages} >
            Upload
          </Button>
        </div> */}
      </label>
      {/* <Grid container xs={12} direction='row' rowGap={1} columnGap={1}>
  {
    currentFiles.length ? currentFiles.map((image, index) => (
        // <div style={{ height: '150px', width: '150px', display:'inline-block' }}>
          <Preview id='Hey There!' style={{backgroundImage: image.tempURL}} onClick={(event)=>{console.log(event.target, image)}}>
            <Del id='image.id' onClick={(event)=>{console.log(event.target)}} />
            <img alt='' id={image.id} src={image.tempURL} style={{ flexShrink: 0
, width: '100%', objectFit: 'cover' }} />
          </Preview>
        // </div>
    )) : null
  }
  </Grid> */}
  
      <Grid container item xs={12} direction='row'
        rowGap={1}
        columnGap='1%'
      >
        {/* <ImageUploadGallery onSortEnd={onSortEnd} axis='xy' removeExistingFile={removeExistingFile} removeFile={removeFile} images={images} /> */}
        {
        //   existingImages.map((image) => {
        //     return <ImageUploadThumbnail id={image._id} url={image.url} key={image._id} removeFile={removeExistingFile} />
        //   })
        // }
        // {
        //   images.map((image) => {
        //     return <ImageUploadThumbnail image={image} id={image.id} url={image.tempURL} key={image._id ? image._id : image.id} removeFile={removeFile} />
        //   })
        }
      </Grid>
      
      <ImageUploadGallery onSortEnd={onSortEnd} axis='xy' removeFile={removeFile} allImages={allImages} />
    </Grid >
  );
}

